CREATE OR REPLACE FUNCTION audit_log_seal() RETURNS trigger AS $$
DECLARE
    v_prev   text;
    v_input  text;
    c_genesis constant text := repeat('0', 64);
BEGIN
    -- Serialise audit appends so the prev_hash read + row_hash write are atomic
    -- across concurrent transactions (re-entrant within one txn). Released at commit.
    PERFORM pg_advisory_xact_lock(4915623420);

    NEW.seq := nextval('audit_log_seq');

    SELECT row_hash INTO v_prev
    FROM audit_log
    WHERE row_hash IS NOT NULL
    ORDER BY seq DESC
    LIMIT 1;

    IF v_prev IS NULL THEN
        v_prev := c_genesis;
    END IF;
    NEW.prev_hash := v_prev;

    v_input := COALESCE(NEW.seq::text, '') || '|' || v_prev || '|'
        || COALESCE(NEW.action, '') || '|'
        || COALESCE(NEW.entity_type, '') || '|'
        || COALESCE(NEW.entity_id::text, '') || '|'
        || COALESCE(NEW.patient_code, '') || '|'
        || COALESCE(NEW.performed_by, '') || '|'
        || COALESCE(NEW.branch_code, '') || '|'
        || COALESCE(NEW.ip_address, '') || '|'
        || to_char(NEW.timestamp, 'YYYY-MM-DD"T"HH24:MI:SS.US') || '|'
        || COALESCE(NEW.details::text, '');

    NEW.row_hash := encode(digest(v_input, 'sha256'), 'hex');
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_audit_log_seal ON audit_log;
CREATE TRIGGER trg_audit_log_seal
    BEFORE INSERT ON audit_log
    FOR EACH ROW EXECUTE FUNCTION audit_log_seal();

CREATE OR REPLACE FUNCTION audit_log_block_mutation() RETURNS trigger AS $$
BEGIN
    RAISE EXCEPTION 'audit_log is append-only and tamper-evident; % is not permitted', TG_OP
        USING ERRCODE = 'check_violation';
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_audit_log_no_update_delete ON audit_log;
CREATE TRIGGER trg_audit_log_no_update_delete
    BEFORE UPDATE OR DELETE ON audit_log
    FOR EACH ROW EXECUTE FUNCTION audit_log_block_mutation();

DROP TRIGGER IF EXISTS trg_audit_log_no_truncate ON audit_log;
CREATE TRIGGER trg_audit_log_no_truncate
    BEFORE TRUNCATE ON audit_log
    FOR EACH STATEMENT EXECUTE FUNCTION audit_log_block_mutation();
